function renderChats(){if(!state.agents.length)return empty("C","No agents configured","+ Agent",()=>agentForm());if(!state.projects.length)return empty("C","No projects imported","+ Project",()=>projectForm());const previous=$("#chatForm textarea, #newChatForm textarea"),restoreFocus=document.activeElement===previous,selection=restoreFocus?[previous.selectionStart,previous.selectionEnd]:null,active=state.chats.find(c=>c.id===state.activeChatID);$("#content").innerHTML=`<div class="chat-layout"><aside class="chat-list"><button class="chat-list-new ${active?"":"active"}" id="chatListNew"><span>＋</span><b>New chat</b></button>${state.chats.length?state.chats.map(c=>`<button class="chat-list-item ${c.id===state.activeChatID?"active":""}" data-chat-id="${c.id}"><b>${esc(c.title)}</b><span>${esc(c.agent_type)} · ${esc(c.project_name)}</span><small>${esc(c.task_title||"")}</small></button>`).join(""):'<p class="chat-list-empty">Your conversations will appear here.</p>'}</aside><section class="chat-panel ${active?"":"chat-panel-new"}">${active?chatPanel(active):newChatPanel()}</section></div>`;$("#chatListNew").onclick=()=>startChatDraft();$("#content").querySelectorAll("[data-chat-id]").forEach(b=>b.onclick=()=>openChat(+b.dataset.chatId));if(active)wireChatPanel(active);else wireNewChatPanel();const composer=$("#chatForm textarea, #newChatForm textarea");if(restoreFocus&&composer){composer.focus();composer.setSelectionRange(...selection)}}
function chatAgentOptions(selected){return state.agents.map(a=>`<option value="${a.id}" ${a.id===selected?"selected":""}>${esc(a.type)} (${esc(a.status)})</option>`).join("")}
function newChatPanel(){const d=ensureChatDraft(),agent=state.agents.find(a=>a.id===d.agent),project=state.projects.find(p=>p.id===d.project),task=state.tasks.find(t=>t.id===d.task);return `<div class="chat-start"><div class="chat-start-copy"><div class="empty-icon">C</div><h2>Start a conversation</h2><p>${esc(agent?.type)} will work in ${esc(project?.name)}${task?` with ${esc(taskDisplayID(task))} ${esc(task.title)} as context`:""}.</p></div><form class="chat-start-compose" id="newChatForm"><textarea name="content" placeholder="What do you want to work on?" required autofocus>${esc(state.chatInputs.new)}</textarea><select class="chat-agent-select" name="agent_id" aria-label="Agent">${chatAgentOptions(d.agent)}</select><button class="primary" ${state.chatLoading?"disabled":""}>Send</button></form></div>`}
function chatPanel(chat){const selected=state.chatDraft.agent||chat.agent_id;return `<div class="chat-head"><div><h2>${esc(chat.title)}</h2><p>${esc(chat.agent_type)} · ${esc(chat.project_name)} · ${esc(chat.task_title)}</p></div><button id="chatTask">Task</button></div><div class="chat-messages" id="chatMessages">${state.chatLoading?'<div class="muted">Loading...</div>':chatMessagesHTML()}</div><form class="chat-compose" id="chatForm"><textarea name="content" placeholder="Message the agent" required>${esc(state.chatInputs[chat.id]||"")}</textarea><select class="chat-agent-select" name="agent_id" aria-label="Agent">${chatAgentOptions(selected)}</select><button class="primary" ${state.chatLoading?"disabled":""}>Send</button></form>`}
function chatMessagesHTML(){if(!state.chatMessages.length)return `<div class="empty chat-empty"><div><div class="empty-icon">C</div><div>Start the conversation</div></div></div>`;return state.chatMessages.map(m=>{const answer=chatAnswer(m),running=m.run&&["queued","starting","running","waiting_approval"].includes(m.run.status),logs=m.logs||[];return `<div class="chat-turn"><div class="chat-bubble agent"><b>Agent</b><pre>${esc(answer|| (running?"Working...":"No response yet"))}</pre>${chatTaskProposalHTML(m)}<details class="chat-details" data-message-id="${m.id}" ${state.chatDetails[m.id]?"open":""}><summary>Show details</summary><div class="chat-detail"><b>You</b><pre>${esc(m.content)}</pre></div>${m.run?`<div class="chat-detail"><b>Run</b><div>${badge(m.run.status)} <span class="muted">#${m.run.id}</span></div></div>`:""}<div class="chat-detail"><b>Logs</b><div class="chat-detail-logs">${logs.length?logs.map(l=>`<div class="log ${esc(l.stream)}"><b>${esc(l.stream)}</b> ${esc(l.content)}</div>`).join(""):'<div class="log">No output yet</div>'}</div></div></details></div></div>`}).join("")}
function chatAnswer(m){const logs=m.logs||[],assistant=logs.filter(l=>l.stream==="assistant"),answer=latestLogLines(assistant.length?assistant:logs,80);return answer.replace(/```tailagent_tasks[\s\S]*?```/g,"").trim()}
function chatTaskProposalHTML(m){const p=m.task_proposal;if(!p)return "";const chat=state.chats.find(c=>c.id===state.activeChatID),created=p.status==="created";return `<section class="chat-task-proposal"><div class="chat-task-proposal-head"><div><b>${p.tasks.length} task${p.tasks.length===1?"":"s"} for ${esc(chat?.project_name||"project")}</b><span>${created?"Created":"Review before creating"}</span></div>${badge(created?"created":"pending")}</div><div class="chat-task-proposal-list">${p.tasks.map(t=>{const milestone=state.milestones.find(x=>x.id===t.milestone_id);return `<article><b>${esc(t.title)}</b>${t.description?`<p>${esc(t.description)}</p>`:""}<small>Milestone: ${esc(milestone&&!milestone.is_default_none?milestone.name:"None")}</small></article>`}).join("")}</div>${created?`<div class="chat-task-created">Created task IDs: ${p.created_task_ids.map(id=>`#${id}`).join(", ")}</div>`:`<button class="primary chat-create-tasks" data-message-id="${m.id}">Create ${p.tasks.length} task${p.tasks.length===1?"":"s"}</button>`}</section>`}
async function openChat(id,rerender=true){const chat=state.chats.find(c=>c.id===id);if(chat)Object.assign(state.chatDraft,{agent:chat.agent_id,project:chat.project_id,task:chat.task_id});state.activeChatID=id;state.chatLoading=true;if(rerender)renderChats();try{state.chatMessages=await api(`/api/chats/${id}/messages`)}catch(x){flash(x.message,true)}finally{state.chatLoading=false;if(state.view==="chats")renderChats()}}
function wireChatSubmitOnEnter(form){form.content.onkeydown=e=>{if(e.key==="Enter"&&!e.shiftKey&&!e.isComposing){e.preventDefault();form.requestSubmit()}}}
function wireChatPanel(chat){$("#chatTask").onclick=()=>taskView(state.tasks.find(t=>t.id===chat.task_id)||{id:chat.task_id,title:chat.task_title,project_name:chat.project_name,milestone_name:"",status:"todo"});const body=$("#chatMessages"),form=$("#chatForm");body.querySelectorAll(".chat-details").forEach(d=>d.ontoggle=()=>state.chatDetails[d.dataset.messageId]=d.open);body.querySelectorAll(".chat-create-tasks").forEach(b=>b.onclick=async()=>{b.disabled=true;try{const tasks=await api(`/api/chats/${chat.id}/tasks`,{method:"POST",body:JSON.stringify({message_id:+b.dataset.messageId})});flash(`${tasks.length} task${tasks.length===1?"":"s"} created`);await load();await openChat(chat.id)}catch(x){flash(x.message,true);b.disabled=false}});body.scrollTop=body.scrollHeight;form.agent_id.onchange=()=>state.chatDraft.agent=+form.agent_id.value;form.content.oninput=()=>state.chatInputs[chat.id]=form.content.value;wireChatSubmitOnEnter(form);form.onsubmit=async e=>{e.preventDefault();const content=e.target.content.value.trim();if(!content)return;const agentID=+e.target.agent_id.value;state.chatDraft.agent=agentID;state.chatLoading=true;renderChats();try{state.chatMessages=await api(`/api/chats/${chat.id}/messages`,{method:"POST",body:JSON.stringify({content,agent_id:agentID})});state.chatInputs[chat.id]="";await load();await openChat(chat.id)}catch(x){flash(x.message,true);state.chatLoading=false;renderChats()}}}
function wireNewChatPanel(){const form=$("#newChatForm");form.agent_id.onchange=()=>state.chatDraft.agent=+form.agent_id.value;form.content.oninput=()=>state.chatInputs.new=form.content.value;wireChatSubmitOnEnter(form);form.onsubmit=async e=>{e.preventDefault();const content=e.target.content.value.trim();if(!content)return;const d=ensureChatDraft(),agentID=+e.target.agent_id.value,title=content.split("\n")[0].trim().slice(0,60)||"Chat";state.chatDraft.agent=agentID;state.chatLoading=true;renderChats();try{const chat=await api("/api/chats",{method:"POST",body:JSON.stringify({agent_id:agentID,project_id:d.project,task_id:d.task,title})});state.activeChatID=chat.id;state.chatMessages=await api(`/api/chats/${chat.id}/messages`,{method:"POST",body:JSON.stringify({content,agent_id:agentID})});state.chatInputs.new="";await load();await openChat(chat.id)}catch(x){flash(x.message,true);state.chatLoading=false;renderChats()}}}
function chatForm({task}={}){if(!state.agents.length)return flash("Add an agent before starting a chat.",true);if(!state.projects.length)return flash("Import a project first.",true);startChatDraft({agent:task?.assigned_agent_id||state.agents.find(a=>a.status==="ready")?.id||state.agents[0].id,project:task?.project_id||state.filters.project||state.projects[0].id,task:task?.id||0})}
function renderTraces(){addAction("Refresh",load);const points=Array(24).fill(0);state.traces.forEach(t=>points[new Date(t.created_at).getHours()]++);const max=Math.max(...points,1),path=points.map((v,i)=>`${i?"L":"M"} ${i*40} ${120-v/max*105}`).join(" "),f=state.traceFilters;$("#content").innerHTML=`<div class="trace-layout"><div class="filters">${field("Search","search",f.search,"text",'id="traceSearch"')}${select("Project","project",[{value:0,label:"All projects"},...projectOptions()],f.project)}${select("Agent","agent",[{value:0,label:"All agents"},...state.agents.map(a=>({value:a.id,label:a.type}))],f.agent)}${select("Status","status",[{value:"",label:"All statuses"},...["running","success","error","waiting_approval","cancelled"].map(x=>({value:x,label:x}))],f.status)}${select("Task","task",[{value:0,label:"All tasks"},...state.tasks.map(t=>({value:t.id,label:`${taskDisplayID(t)} ${t.title}`}))],f.task)}</div><div><div class="chart"><svg viewBox="0 0 920 130" preserveAspectRatio="none"><line class="gridline" x1="0" y1="120" x2="920" y2="120"/><path class="chartline" d="${path}"/></svg></div><table><thead><tr><th>Time</th><th>Status</th><th>Agent</th><th>Project</th><th class="task-id-column">Task</th><th>Event</th><th>Message</th></tr></thead><tbody id="traceRows"></tbody></table></div></div>`;const update=()=>{Object.assign(f,{search:$("#traceSearch").value,project:+$("[name=project]").value,agent:+$("[name=agent]").value,status:$("[name=status]").value,task:+$("[name=task]").value});const q=f.search.toLowerCase(),list=state.traces.filter(t=>{const run=state.runs.find(r=>r.id===t.run_id);return (!q||(t.message||"").toLowerCase().includes(q))&&(!f.project||run?.project_id===f.project)&&(!f.agent||run?.agent_id===f.agent)&&(!f.status||t.status===f.status)&&(!f.task||run?.task_id===f.task)});$("#traceRows").innerHTML=list.map(t=>{const run=state.runs.find(r=>r.id===t.run_id),task=state.tasks.find(task=>task.id===run?.task_id);return `<tr data-id="${t.id}"><td>${new Date(t.created_at).toLocaleTimeString()}</td><td>${badge(t.status)}</td><td>${esc(t.agent_type)}</td><td>${esc(t.project_name)}</td><td class="task-id-column">${task?`<button class="table-link" data-task-id="${task.id}" title="${esc(task.title)}">${esc(taskDisplayID(task))}</button>`:"—"}</td><td>${esc(t.event_type)}</td><td>${esc(t.message)}</td></tr>`}).join("");$("#traceRows").querySelectorAll("tr").forEach(r=>r.onclick=()=>traceView(state.traces.find(t=>t.id==r.dataset.id)));$("#traceRows").querySelectorAll("[data-task-id]").forEach(b=>b.onclick=e=>{e.stopPropagation();taskView(state.tasks.find(t=>t.id==b.dataset.taskId))})};$("#traceSearch").oninput=update;["project","agent","status","task"].forEach(n=>$(`[name=${n}]`).onchange=update);update()}
function traceView(t){drawer(t.event_type,`${t.agent_type} · ${t.status}`,`<div class="section"><div class="kv"><span>Trace ID</span><code>${esc(t.trace_id)}</code></div><div class="kv"><span>Run ID</span><b>${t.run_id}</b></div><div class="kv"><span>Project</span><b>${esc(t.project_name)}</b></div><div class="kv"><span>Task</span><b>${esc(t.task_title)}</b></div><div class="kv"><span>Message</span><div>${esc(t.message)}</div></div><div class="kv"><span>Attributes</span><pre>${esc(JSON.stringify(t.attributes||{},null,2))}</pre></div></div><button id="traceLogs">Run logs</button>`);$("#traceLogs").onclick=()=>showLogs(state.runs.find(r=>r.id===t.run_id))}
function renderSettings(){const s=state.settings;$("#content").innerHTML=`<form id="settingsForm" class="settings">${field("Workspace root","workspace_root",s.workspace_root||"")}${field("SQLite database path","database_path",s.database_path||"","text","disabled")}${field("Approval timeout (seconds)","approval_timeout_seconds",s.approval_timeout_seconds||300,"number","min=1")}${field("Default shell","default_shell",s.default_shell||"")}${field("Max concurrent agents","max_concurrent_agents",s.max_concurrent_agents||2,"number","min=1")}${field("Trace retention (days)","trace_retention_days",s.trace_retention_days||30,"number","min=1")}${field("Optional OTel endpoint","otel_endpoint",s.otel_endpoint||"")}<button class="primary">Save settings</button></form>`;$("#settingsForm").onsubmit=async e=>{e.preventDefault();const v=Object.fromEntries(new FormData(e.target));["approval_timeout_seconds","max_concurrent_agents","trace_retention_days"].forEach(k=>v[k]=+v[k]);v.database_path=s.database_path;try{state.settings=await api("/api/settings",{method:"PUT",body:JSON.stringify(v)});flash("Settings saved")}catch(x){flash(x.message,true)}}}
function addAction(label,fn){$("#actions").innerHTML=`<button class="primary" id="primaryAction">${label}</button>`;$("#primaryAction").onclick=fn}
load().catch(e=>flash(e.message,true));setInterval(()=>{if(state.view==="chats"&&state.activeChatID)openChat(state.activeChatID).catch(()=>{});else if(["approvals","traces","tasks"].includes(state.view))load().catch(()=>{})},5000);
